from dataclasses import dataclass
from typing import Optional, Dict, List
from enum import Enum


class Side(Enum):
    HOME = "home"
    AWAY = "away"


@dataclass
class BlowoutSignal:
    """Signal generated by late game blowout strategy."""
    timestamp: float
    game_id: str
    leading_team: Side
    score_differential: int
    home_score: int
    away_score: int
    period: int
    time_remaining_seconds: int
    win_probability: float
    confidence: str


@dataclass
class BlowoutStrategyConfig:
    """Configuration for late game blowout strategy."""
    min_point_differential: int = 12
    max_time_remaining_seconds: int = 600
    min_period: int = 4
    high_confidence_threshold: int = 15
    very_high_confidence_threshold: int = 20
    base_position_size: float = 5.0
    max_buy_price: float = 0.92
    min_edge_required: float = 0.02


